#include <cstdio>
#include <cstring>
#include <cstdlib>

#include "config_settings_parse.h"
#include "opt_str_mng.h"

//================================================================================================================================
//=> - Globals -
//================================================================================================================================

typedef const char* cstr;

static StringManager g_unit_names;

static const char* G_CFG_PATH = "../game_config.settings";
static const char* G_UNIT_PATH = "../game_config.units";

//================================================================================================================================
//=> - Unit name table -
//================================================================================================================================

static void trim_ws_idx (StringManager& sm, u32 idx) {
    sm.trim_head_char(idx, ' ');
    sm.trim_tail_char(idx, ' ');
    sm.trim_head_char(idx, '\t');
    sm.trim_tail_char(idx, '\t');
    sm.trim_head_char(idx, '\r');
    sm.trim_tail_char(idx, '\r');
    sm.trim_head_char(idx, '\n');
    sm.trim_tail_char(idx, '\n');
}

static void trim_ws_all (StringManager& sm) {
    for (u32 i = 0; i < sm.get_string_count(); ++i) {
        trim_ws_idx(sm, i);
    }
}

static bool load_unit_names (cstr path) {
    StringManager lines;
    if (!lines.load_file_content(path)) {
        std::printf("ERROR: could not load unit names '%s'\n", path);
        return false;
    }
    lines.split_string_by_char(0, '\n');
    trim_ws_all(lines);
    lines.cull_empty_strings();
    u32 tot = 0;
    for (u32 i = 0; i < lines.get_string_count(); ++i) {
        StringManager parts;
        parts.load_cstr_content(lines.get_string_content(i));
        parts.split_string_by_char(0, ':');
        if (parts.get_string_count() == 0) {
            continue;
        }
        trim_ws_idx(parts, 0);
        cstr name = parts.get_string_content(0);
        if (name[0] == '\0') {
            continue;
        }
        tot += static_cast<u32>(std::strlen(name)) + 1;
    }
    if (tot == 0) {
        std::printf("ERROR: no unit names in '%s'\n", path);
        return false;
    }
    char* buf = new char[tot];
    u32 k = 0;
    for (u32 i = 0; i < lines.get_string_count(); ++i) {
        StringManager parts;
        parts.load_cstr_content(lines.get_string_content(i));
        parts.split_string_by_char(0, ':');
        if (parts.get_string_count() == 0) {
            continue;
        }
        trim_ws_idx(parts, 0);
        cstr name = parts.get_string_content(0);
        if (name[0] == '\0') {
            continue;
        }
        u32 len = static_cast<u32>(std::strlen(name));
        std::memcpy(buf + k, name, len);
        k += len;
        buf[k++] = '\n';
    }
    if (k > 0) {
        --k;
    }
    buf[k] = '\0';
    g_unit_names.load_cstr_content(buf);
    g_unit_names.split_string_by_char(0, '\n');
    g_unit_names.cull_empty_strings();
    delete[] buf;
    return true;
}

static cstr unit_idx_to_name (u16 idx) {
    if (idx < g_unit_names.get_string_count()) {
        return g_unit_names.get_string_content(idx);
    }
    return "?";
}

static u16 unit_name_to_idx (cstr name) {
    if (name == nullptr) {
        return U16_KEY_NULL;
    }
    StringManager target;
    target.load_cstr_content(name);
    trim_ws_idx(target, 0);
    cstr target_s = target.get_string_content(0);
    for (u32 i = 0; i < g_unit_names.get_string_count(); ++i) {
        if (std::strcmp(g_unit_names.get_string_content(i), target_s) == 0) {
            return static_cast<u16>(i);
        }
    }
    return U16_KEY_NULL;
}

//================================================================================================================================
//=> - Print -
//================================================================================================================================

static void print_config (const GameConfigSettings& cfg) {
    std::printf("GameConfigSettings is_default=%d\n", cfg.is_default() ? 1 : 0);
    
    std::printf("  PATH_MP_TURN: %u\n", cfg.get_mov_pt_per_turn());
    {
        ConfigListUnit lst = cfg.get_start_units();
        std::printf("  START_UNITS:");
        for (u16 i = 0; i < lst.n; ++i) {
            std::printf(" %s", unit_idx_to_name(lst.keys[i].value()));
        }
        std::printf("\n");
    }
    {
        ConfigListUnit lst = cfg.get_start_exp_units();
        std::printf("  START_EXP_UNITS:");
        for (u16 i = 0; i < lst.n; ++i) {
            std::printf(" %s", unit_idx_to_name(lst.keys[i].value()));
        }
        std::printf("\n");
    }
}

//================================================================================================================================
//=> - Main -
//================================================================================================================================

int main (int argc, char* argv[]) {
    cstr cfg_path = G_CFG_PATH;
    cstr unit_path = G_UNIT_PATH;
    if (argc > 1) {
        cfg_path = argv[1];
    }
    if (argc > 2) {
        unit_path = argv[2];
    }
    if (!load_unit_names(unit_path)) {
        return 1;
    }
    NameToIdxCbs cbs = {};
    cbs.unit_name_to_idx = unit_name_to_idx;
    GameConfigSettingsParser psr(cbs);
    GameConfigSettings cfg;
    if (!psr.load_file(cfg_path, &cfg)) {
        return 1;
    }
    print_config(cfg);
    return 0;
}

